import React from 'react';

function DottedSphere({ size = 600, className = '' }) {
  const dots = [];
  const numLatitudes = 20;
  const numLongitudes = 40;

  for (let lat = 0; lat < numLatitudes; lat++) {
    const theta = (lat / numLatitudes) * Math.PI;
    const y = Math.cos(theta) * (size / 2.5);
    const ringRadius = Math.sin(theta) * (size / 2.5);
    const dotsInRing = Math.floor(numLongitudes * Math.sin(theta)) + 1;

    for (let lon = 0; lon < dotsInRing; lon++) {
      const phi = (lon / dotsInRing) * Math.PI * 2;
      const x = Math.cos(phi) * ringRadius;
      const z = Math.sin(phi) * ringRadius;

      // 3D to 2D projection
      const scale = (z + size) / (size * 1.5);
      const projX = x * scale + size / 2;
      const projY = y * scale + size / 2;

      // Depth-based opacity and size
      const depth = (z + size / 2.5) / size;
      const opacity = 0.15 + depth * 0.7;
      const dotSize = 1 + depth * 2;

      dots.push({ x: projX, y: projY, opacity, size: dotSize, depth });
    }
  }

  return (
    <div className={`absolute pointer-events-none ${className}`} style={{
      width: size,
      height: size,
    }}>
      <style>{`
        @keyframes sphereSpin {
          0% { transform: rotateY(0deg); }
          100% { transform: rotateY(360deg); }
        }
        @keyframes gentlePulse {
          0%, 100% { opacity: 0.8; }
          50% { opacity: 1; }
        }
        .sphere-wrapper {
          animation: gentlePulse 6s ease-in-out infinite;
        }
      `}</style>
      <div className="sphere-wrapper" style={{ width: '100%', height: '100%' }}>
        <svg width={size} height={size} viewBox={`0 0 ${size} ${size}`}>
          <defs>
            <radialGradient id="bgGlow" cx="50%" cy="50%" r="50%">
              <stop offset="0%" stopColor="#8b5cf6" stopOpacity="0.15" />
              <stop offset="50%" stopColor="#6366f1" stopOpacity="0.08" />
              <stop offset="100%" stopColor="#3b82f6" stopOpacity="0" />
            </radialGradient>
          </defs>

          {/* Subtle glow behind */}
          <circle cx={size/2} cy={size/2} r={size/2.2} fill="url(#bgGlow)" />

          {/* Dots sorted by depth for proper layering */}
          {dots.sort((a, b) => a.depth - b.depth).map((dot, i) => (
            <circle
              key={i}
              cx={dot.x}
              cy={dot.y}
              r={dot.size}
              fill={`rgba(167, 139, 250, ${dot.opacity})`}
              style={{
                filter: dot.depth > 0.5 ? 'blur(0px)' : 'blur(0.5px)'
              }}
            />
          ))}
        </svg>
      </div>
    </div>
  );
}

export default DottedSphere;
